module top_module(
    input  VPWR,
    input  UDP_IN,
    input  CLK,
    output UDP_OUT
);reg obf_pwrgood;

    always @(posedge CLK) begin
        if (UDP_IN) begin
            obf_pwrgood <= 0;
        end else begin
            obf_pwrgood <= VPWR;
        end
    end

    assign UDP_OUT = obf_pwrgood;

endmodule
